// ── HMAC-SHA256 verification ────────────────────────────────────────────────
// rawBody is available because the webhook was set with options.rawBody = true
const rawBody = $input.item.json.rawBody || JSON.stringify($input.item.json.body || $input.item.json);
const headers = $input.item.json.headers || {};
const signature = headers['x-razorpay-signature'] || '';
const WEBHOOK_SECRET = 'YOUR_RAZORPAY_WEBHOOK_SECRET';

let valid = false;
try {
  const encoder = new TextEncoder();
  const key = await crypto.subtle.importKey(
    'raw', encoder.encode(WEBHOOK_SECRET),
    { name: 'HMAC', hash: 'SHA-256' }, false, ['sign']
  );
  const sigBuf = await crypto.subtle.sign('HMAC', key, encoder.encode(rawBody));
  const expected = Array.from(new Uint8Array(sigBuf)).map(b => b.toString(16).padStart(2,'0')).join('');
  valid = expected === signature;
} catch(e) {
  valid = false;
}

// ── Parse event ─────────────────────────────────────────────────────────────
let event = {};
try { event = JSON.parse(rawBody); } catch(e) { event = {}; }

const eventType = event?.event || '';
const payment = event?.payload?.payment?.entity || {};
const paymentLink = event?.payload?.payment_link?.entity || {};

// notes live on the payment_link entity for payment_link.paid events
const notes = paymentLink.notes || payment.notes || {};

// Strip country code prefix from contact for consistent storage
const rawContact = payment.contact || notes.sender || '';
const sender = rawContact.replace(/^\+?91/, '');

return [{ json: {
  valid,
  eventType,
  paymentId: payment.id || '',
  paymentAmount: payment.amount || 0,
  paymentLinkId: paymentLink.id || notes.razorpay_payment_link_id || '',
  notes,
  sender,
  itemName: notes.item_name || '',
  qty: parseInt(notes.qty) || 1,
  price: parseFloat(notes.price) || 0,
  BUSINESS_ACCOUNT_ID: notes.business_account_id || ''
} }];

const ctx = $('Verify & Parse').item.json;
const tokenNum = $('Create Order Token').item.json.token_number;
const prefix = $('Increment Token Counter').item.json.token_prefix || 'T';
const total = parseFloat($('Lookup Pending Sale').item.json.total);
const avgPrep = 15; // could read from restaurant_config

const reply = `✅ *Payment Received!*

🎫 Your Token: *${prefix}${tokenNum}*

📦 ${ctx.qty}× ${ctx.itemName}
💰 Paid: ₹${total.toFixed(0)}
⏱ Est. ready in ~${avgPrep} min

We will notify you when your order is ready!
_Type *status* to check anytime._`;

return [{ json: { reply, sender: ctx.sender } }];
